import{_ as a,c as r,o as t,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"z.ai 통합: 능력 경계 상세 설명 | Antigravity-Manager","description":"Antigravity Tools의 z.ai 통합 경계를 파악합니다. 요청 라우팅, dispatch_mode 분산, 모델 매핑, Header 보안 정책, 그리고 MCP 리버스 프록시 및 제한 사항을 이해하고 오용을 방지합니다.","frontmatter":{"title":"z.ai 통합: 능력 경계 상세 설명 | Antigravity-Manager","sidebarTitle":"z.ai 경계 요약","subtitle":"z.ai 통합: 능력 경계 상세 설명","description":"Antigravity Tools의 z.ai 통합 경계를 파악합니다. 요청 라우팅, dispatch_mode 분산, 모델 매핑, Header 보안 정책, 그리고 MCP 리버스 프록시 및 제한 사항을 이해하고 오용을 방지합니다.","tags":["z.ai","MCP","Claude","능력 경계"],"prerequisite":["start-getting-started","platforms-mcp"],"order":3},"headers":[],"relativePath":"ko/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md","filePath":"ko/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"}'),i={name:"ko/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"};function d(c,e,l,s,n,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="z-ai-통합의-능력-경계-구현됨-vs-명확히-미구현됨" tabindex="-1">z.ai 통합의 능력 경계 (구현됨 vs 명확히 미구현됨) <a class="header-anchor" href="#z-ai-통합의-능력-경계-구현됨-vs-명확히-미구현됨" aria-label="Permalink to &quot;z.ai 통합의 능력 경계 (구현됨 vs 명확히 미구현됨)&quot;">​</a></h1><p>이 문서는 Antigravity Tools의 z.ai &quot;경계&quot;만 설명하며 &quot;연결 방법&quot;은 설명하지 않습니다. 특정 기능이 작동하지 않는 것을 발견하면 여기서 먼저 확인하세요: 켜지지 않은 것인지, 구성되지 않은 것인지, 아니면 아예 구현되지 않은 것인지.</p><h2 id="학습-후-가능한-작업" tabindex="-1">학습 후 가능한 작업 <a class="header-anchor" href="#학습-후-가능한-작업" aria-label="Permalink to &quot;학습 후 가능한 작업&quot;">​</a></h2><ul><li>z.ai에 기대할 수 있는 작업 판단: &quot;구현됨&quot;과 &quot;문서에서 명확히 미구현&quot; 구분</li><li>z.ai가 영향을 미치는 엔드포인트 확인 (완전히 영향을 받지 않는 엔드포인트도 있음)</li><li>각 결론의 소스코드/문서 증거 확인 (GitHub 행 번호 링크 포함), 직접 검증 가능</li></ul><h2 id="현재-어려움" tabindex="-1">현재 어려움 <a class="header-anchor" href="#현재-어려움" aria-label="Permalink to &quot;현재 어려움&quot;">​</a></h2><p>이미 Antigravity Tools에서 z.ai를 열었지만 사용할 때 다음 의문이 발생할 수 있습니다:</p><ul><li>왜 어떤 요청은 z.ai를 통해 가고 어떤 요청은 전혀 가지 않는가?</li><li>MCP 엔드포인트를 &quot;완전한 MCP Server&quot;로 사용할 수 있는가?</li><li>UI에서 볼 수 있는 스위치가 실제 구현에 대응되어 있는가?</li></ul><h2 id="이-프로젝트에서-z-ai-통합이란" tabindex="-1">이 프로젝트에서 z.ai 통합이란? <a class="header-anchor" href="#이-프로젝트에서-z-ai-통합이란" aria-label="Permalink to &quot;이 프로젝트에서 z.ai 통합이란?&quot;">​</a></h2><p><strong>z.ai 통합</strong>은 Antigravity Tools에서 선택 가능한 &quot;업스트림 provider + MCP 확장&quot;입니다. 특정 조건에서만 Claude 프로토콜 요청을接管하고 MCP Search/Reader 리버스 프록시와 최소한의 Vision MCP 내장 서버를 제공합니다. 전체 프로토콜, 전체 능력의 대체 솔루션이 아닙니다.</p><div class="info custom-block"><p class="custom-block-title">한 문장 기억</p><p>z.ai를 &quot;Claude 요청의 선택 가능한 업스트림 + 스위치 가능한 MCP 엔드포인트 그룹&quot;으로 생각하고, &quot;z.ai의 모든 능력을 완전히 가져온 것&quot;으로 생각하지 마세요.</p></div><h2 id="구현됨-안정적으로-사용-가능-소스코드-기준" tabindex="-1">구현됨: 안정적으로 사용 가능 (소스코드 기준) <a class="header-anchor" href="#구현됨-안정적으로-사용-가능-소스코드-기준" aria-label="Permalink to &quot;구현됨: 안정적으로 사용 가능 (소스코드 기준)&quot;">​</a></h2><h3 id="_1-claude-프로토콜만-z-ai를-통과함-v1-messages-v1-messages-count-tokens" tabindex="-1">1) Claude 프로토콜만 z.ai를 통과함 (/v1/messages + /v1/messages/count_tokens) <a class="header-anchor" href="#_1-claude-프로토콜만-z-ai를-통과함-v1-messages-v1-messages-count-tokens" aria-label="Permalink to &quot;1) Claude 프로토콜만 z.ai를 통과함 (/v1/messages + /v1/messages/count_tokens)&quot;">​</a></h3><p>z.ai의 Anthropic 업스트림 포워딩은 Claude handler의 z.ai 분기에서만 발생합니다:</p><ul><li><code>POST /v1/messages</code>: <code>use_zai=true</code>일 때 <code>forward_anthropic_json(...)</code>을 호출하여 JSON 요청을 z.ai Anthropic 호환 엔드포인트로 포워딩</li><li><code>POST /v1/messages/count_tokens</code>: z.ai 활성화 시 동일하게 포워딩, 그렇지 않으면 자리 표시자 <code>{input_tokens:0, output_tokens:0}</code> 반환</li></ul><p>증거:</p><ul><li>z.ai 분기 선택 및 포워딩 진입점: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>count_tokens의 z.ai 분기 및 자리 표시자 반환: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>z.ai Anthropic 포워딩 구현: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><div class="tip custom-block"><p class="custom-block-title">&quot;응답 스트리밍&quot; 이해 방법</p><p><code>forward_anthropic_json</code>은 업스트림 응답 본문을 <code>bytes_stream()</code>으로 클라이언트에 스트리밍 방식으로 전달하며 SSE를 파싱하지 않습니다 (<code>providers/zai_anthropic.rs</code>의 Response body 구성 참조).</p></div><h3 id="_2-스케줄링-모드-dispatch-mode-의-실제-의미" tabindex="-1">2) 스케줄링 모드(dispatch_mode)의 &quot;실제 의미&quot; <a class="header-anchor" href="#_2-스케줄링-모드-dispatch-mode-의-실제-의미" aria-label="Permalink to &quot;2) 스케줄링 모드(dispatch_mode)의 &quot;실제 의미&quot;&quot;">​</a></h3><p><code>dispatch_mode</code>는 <code>/v1/messages</code>가 z.ai를 통과하는지 여부를 결정합니다:</p><table tabindex="0"><thead><tr><th>dispatch_mode</th><th>발생하는 작업</th><th>증거</th></tr></thead><tbody><tr><td><code>off</code></td><td>z.ai를 사용하지 않음</td><td><code>src-tauri/src/proxy/config.rs#L20-L37</code> + <code>src-tauri/src/proxy/handlers/claude.rs#L282-L314</code></td></tr><tr><td><code>exclusive</code></td><td>모든 Claude 요청이 z.ai를 통과함</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L285-L314</code></td></tr><tr><td><code>fallback</code></td><td>Google 풀 사용 불가(0 계정 또는 &quot;사용 가능한 계정 없음&quot;)일 때만 z.ai를 통과함</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L288-L305</code></td></tr><tr><td><code>pooled</code></td><td>z.ai를 &quot;추가 1개 슬롯&quot;으로 간주하여 폴링에 참여 (반드시 적중된다는 보장 없음)</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L306-L312</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">pooled의 일반적인 오해</p><p><code>pooled</code>는 &quot;z.ai + Google 계정 풀 모두 사용하고 가중치로 안정적으로 분산&quot;이 아닙니다. 코드에서 명확히 &quot;no strict guarantees&quot;라고 작성되어 있으며, 본질적으로 폴링 슬롯입니다 (<code>slot == 0</code>일 때만 z.ai를 통과).</p></div><h3 id="_3-모델-매핑-claude-모델명이-z-ai의-glm-로-어떻게-변하는가" tabindex="-1">3) 모델 매핑: Claude 모델명이 z.ai의 glm-*로 어떻게 변하는가? <a class="header-anchor" href="#_3-모델-매핑-claude-모델명이-z-ai의-glm-로-어떻게-변하는가" aria-label="Permalink to &quot;3) 모델 매핑: Claude 모델명이 z.ai의 glm-*로 어떻게 변하는가?&quot;">​</a></h3><p>z.ai로 포워딩하기 전, 요청 본문에 <code>model</code> 필드가 있으면 다시 작성됩니다:</p><ol><li><code>proxy.zai.model_mapping</code> 정확히 일치 (원래 문자열과 lower-case key 모두 지원)</li><li><code>zai:&lt;model&gt;</code> 접두사: <code>zai:</code>를 제거하고 직접 사용</li><li><code>glm-*</code>: 변경 없음 유지</li><li><code>claude-*</code> 아님: 변경 없음 유지</li><li><code>claude-*</code>이고 <code>opus/haiku</code> 포함: <code>proxy.zai.models.opus/haiku</code>로 매핑, 그렇지 않으면 기본 <code>sonnet</code></li></ol><p>증거: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L149-L152" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></p><h3 id="_4-포워딩-시-header-보안-정책-로컬-프록시-키-유출-방지" tabindex="-1">4) 포워딩 시 Header 보안 정책 (로컬 프록시 키 유출 방지) <a class="header-anchor" href="#_4-포워딩-시-header-보안-정책-로컬-프록시-키-유출-방지" aria-label="Permalink to &quot;4) 포워딩 시 Header 보안 정책 (로컬 프록시 키 유출 방지)&quot;">​</a></h3><p>z.ai 업스트림 포워딩은 &quot;모든 Header를 그대로 전달&quot;하지 않고 두 가지 방어선을 적용합니다:</p><ul><li>일부 Header만 허용 (예: <code>content-type</code>, <code>accept</code>, <code>anthropic-version</code>, <code>user-agent</code>)</li><li>z.ai의 API Key를 업스트림에 주입 (클라이언트가 사용하는 인증 방법 우선 유지: <code>x-api-key</code> 또는 <code>Authorization: Bearer ...</code>)</li></ul><p>증거:</p><ul><li>Header 허용 목록: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L89" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li><li>z.ai auth 주입: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L91-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><h2 id="구현됨-mcp-search-reader-리버스-프록시-vision-내장" tabindex="-1">구현됨: MCP (Search/Reader 리버스 프록시 + Vision 내장) <a class="header-anchor" href="#구현됨-mcp-search-reader-리버스-프록시-vision-내장" aria-label="Permalink to &quot;구현됨: MCP (Search/Reader 리버스 프록시 + Vision 내장)&quot;">​</a></h2><h3 id="_1-mcp-search-reader-z-ai의-mcp-엔드포인트로-리버스-프록시" tabindex="-1">1) MCP Search/Reader: z.ai의 MCP 엔드포인트로 리버스 프록시 <a class="header-anchor" href="#_1-mcp-search-reader-z-ai의-mcp-엔드포인트로-리버스-프록시" aria-label="Permalink to &quot;1) MCP Search/Reader: z.ai의 MCP 엔드포인트로 리버스 프록시&quot;">​</a></h3><p>로컬 엔드포인트와 업스트림 주소는 하드코딩되어 있습니다:</p><table tabindex="0"><thead><tr><th>로컬 엔드포인트</th><th>업스트림 주소</th><th>스위치</th><th>증거</th></tr></thead><tbody><tr><td><code>/mcp/web_search_prime/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_search_prime/mcp</code></td><td><code>proxy.zai.mcp.web_search_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L115-L135</code></td></tr><tr><td><code>/mcp/web_reader/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_reader/mcp</code></td><td><code>proxy.zai.mcp.web_reader_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L137-L157</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">404는 &quot;네트워크 문제&quot;가 아님</p><p><code>proxy.zai.mcp.enabled=false</code>이거나 해당 <code>web_search_enabled/web_reader_enabled=false</code>이면 이 엔드포인트는 직접 404를 반환합니다.</p></div><p>증거:</p><ul><li>MCP 총 스위치 및 z.ai key 검증: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L52-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>라우팅 등록: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L157-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></li></ul><h3 id="_2-vision-mcp-최소화된-streamable-http-mcp-내장-서버" tabindex="-1">2) Vision MCP: &quot;최소화된 Streamable HTTP MCP&quot; 내장 서버 <a class="header-anchor" href="#_2-vision-mcp-최소화된-streamable-http-mcp-내장-서버" aria-label="Permalink to &quot;2) Vision MCP: &quot;최소화된 Streamable HTTP MCP&quot; 내장 서버&quot;">​</a></h3><p>Vision MCP는 리버스 프록시가 아니라 로컬 내장 구현입니다:</p><ul><li>엔드포인트: <code>/mcp/zai-mcp-server/mcp</code></li><li><code>POST</code> 지원: <code>initialize</code>, <code>tools/list</code>, <code>tools/call</code></li><li><code>GET</code>은 SSE keepalive 반환 (초기화된 세션 필요)</li><li><code>DELETE</code>는 세션 종료</li></ul><p>증거:</p><ul><li>handler 메인 진입점 및 메서드 디스패치: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L376-L397" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li><code>initialize</code>, <code>tools/list</code>, <code>tools/call</code> 구현: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L229-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Vision MCP의 &quot;최소 구현&quot; 위치 지정: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></li></ul><h3 id="_3-vision-mcp-도구-세트-8개-및-파일-크기-제한" tabindex="-1">3) Vision MCP 도구 세트 (8개) 및 파일 크기 제한 <a class="header-anchor" href="#_3-vision-mcp-도구-세트-8개-및-파일-크기-제한" aria-label="Permalink to &quot;3) Vision MCP 도구 세트 (8개) 및 파일 크기 제한&quot;">​</a></h3><p>도구 목록은 <code>tool_specs()</code>에서 가져옵니다:</p><ul><li><code>ui_to_artifact</code></li><li><code>extract_text_from_screenshot</code></li><li><code>diagnose_error_screenshot</code></li><li><code>understand_technical_diagram</code></li><li><code>analyze_data_visualization</code></li><li><code>ui_diff_check</code></li><li><code>analyze_image</code></li><li><code>analyze_video</code></li></ul><p>증거: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L166-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L45-L53" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></p><p>로컬 파일은 읽혀져서 <code>data:&lt;mime&gt;;base64,...</code>로 인코딩되며, 하드 제한이 있습니다:</p><ul><li>이미지 최대 5 MB (<code>image_source_to_content(..., 5)</code>)</li><li>비디오 최대 8 MB (<code>video_source_to_content(..., 8)</code>)</li></ul><p>증거: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L111" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></p><h2 id="명확히-미구현됨-기대하지-마세요-문서-선언-및-구현-세부-사항-기준" tabindex="-1">명확히 미구현됨 / 기대하지 마세요 (문서 선언 및 구현 세부 사항 기준) <a class="header-anchor" href="#명확히-미구현됨-기대하지-마세요-문서-선언-및-구현-세부-사항-기준" aria-label="Permalink to &quot;명확히 미구현됨 / 기대하지 마세요 (문서 선언 및 구현 세부 사항 기준)&quot;">​</a></h2><h3 id="_1-z-ai-사용량-예산-모니터링-usage-budget-미구현됨" tabindex="-1">1) z.ai 사용량/예산 모니터링(usage/budget) 미구현됨 <a class="header-anchor" href="#_1-z-ai-사용량-예산-모니터링-usage-budget-미구현됨" aria-label="Permalink to &quot;1) z.ai 사용량/예산 모니터링(usage/budget) 미구현됨&quot;">​</a></h3><p><code>docs/zai/implementation.md</code>에 명확히 &quot;not implemented yet&quot;이라고 작성되어 있습니다. 이는 다음을 의미합니다:</p><ul><li>Antigravity Tools가 z.ai의 usage/budget 쿼리나 알림을 제공할 것으로 기대할 수 없음</li><li>할당량 관리(Quota Protection)도 z.ai의 예산/사용량 데이터를 자동으로 읽지 않음</li></ul><p>증거: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_2-vision-mcp는-완전한-mcp-server가-아님" tabindex="-1">2) Vision MCP는 완전한 MCP Server가 아님 <a class="header-anchor" href="#_2-vision-mcp는-완전한-mcp-server가-아님" aria-label="Permalink to &quot;2) Vision MCP는 완전한 MCP Server가 아님&quot;">​</a></h3><p>Vision MCP는 현재 &quot;도구 호출만 가능한&quot; 최소 구현으로 지정되어 있습니다: prompts/resources, resumability, streamed tool output 등은 아직 구현되지 않았습니다.</p><p>증거: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L34-L36" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_3-v1-models-claude는-z-ai의-실제-모델-목록을-반영하지-않음" tabindex="-1">3) <code>/v1/models/claude</code>는 z.ai의 실제 모델 목록을 반영하지 않음 <a class="header-anchor" href="#_3-v1-models-claude는-z-ai의-실제-모델-목록을-반영하지-않음" aria-label="Permalink to &quot;3) `/v1/models/claude`는 z.ai의 실제 모델 목록을 반영하지 않음&quot;">​</a></h3><p>이 엔드포인트가 반환하는 모델 목록은 로컬 내장 매핑 및 사용자 정의 매핑(<code>get_all_dynamic_models</code>)에서 가져오며, z.ai 업스트림의 <code>/v1/models</code>를 요청하지 않습니다.</p><p>증거:</p><ul><li>handler: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1162-L1183" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>목록 생성 로직: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></li></ul><h2 id="구성-필드-요약-z-ai-관련" tabindex="-1">구성 필드 요약 (z.ai 관련) <a class="header-anchor" href="#구성-필드-요약-z-ai-관련" aria-label="Permalink to &quot;구성 필드 요약 (z.ai 관련)&quot;">​</a></h2><p>z.ai 구성은 <code>ProxyConfig.zai</code> 아래에 있으며 다음 필드를 포함합니다:</p><ul><li><code>enabled</code> / <code>base_url</code> / <code>api_key</code></li><li><code>dispatch_mode</code> (<code>off/exclusive/pooled/fallback</code>)</li><li><code>model_mapping</code> (정확히 일치하는 항목 덮어쓰기)</li><li><code>models.{opus,sonnet,haiku}</code> (Claude 제품군 기본 매핑)</li><li><code>mcp.{enabled,web_search_enabled,web_reader_enabled,vision_enabled}</code></li></ul><p>기본값(base_url / 기본 모델)도 같은 파일에 있습니다:</p><ul><li><code>base_url = &quot;https://api.z.ai/api/anthropic&quot;</code></li><li><code>opus/sonnet = &quot;glm-4.7&quot;</code></li><li><code>haiku = &quot;glm-4.5-air&quot;</code></li></ul><p>증거: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></p><hr><h2 id="이-장-요약" tabindex="-1">이 장 요약 <a class="header-anchor" href="#이-장-요약" aria-label="Permalink to &quot;이 장 요약&quot;">​</a></h2><ul><li>z.ai는 현재 Claude 프로토콜(<code>/v1/messages</code> + <code>count_tokens</code>)만接管하며, 다른 프로토콜 엔드포인트는 &quot;자동으로 z.ai를 통과&quot;하지 않음</li><li>MCP Search/Reader는 리버스 프록시; Vision MCP는 로컬 최소 구현, 완전한 MCP Server가 아님</li><li><code>/v1/models/claude</code>의 모델 목록은 로컬 매핑에서 가져오며, z.ai 업스트림의 실제 모델을 대표하지 않음</li></ul><hr><h2 id="다음-강의-예고" tabindex="-1">다음 강의 예고 <a class="header-anchor" href="#다음-강의-예고" aria-label="Permalink to &quot;다음 강의 예고&quot;">​</a></h2><blockquote><p>다음 강의에서는 **<a href="./../../changelog/release-notes/">버전 변경 이력</a>**을 학습합니다.</p></blockquote><hr><h2 id="부록-소스코드-참조" tabindex="-1">부록: 소스코드 참조 <a class="header-anchor" href="#부록-소스코드-참조" aria-label="Permalink to &quot;부록: 소스코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스코드 위치 확인</strong></summary><blockquote><p>업데이트 시간: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>z.ai 통합 범위(Claude 프로토콜 + MCP + Vision MCP)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L12-L17" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>12-17</td></tr><tr><td>z.ai 스케줄링 모드 및 기본 모델</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>20-116</td></tr><tr><td>z.ai 기본 base_url / 기본 모델</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>265-279</td></tr><tr><td><code>/v1/messages</code>가 z.ai를 통과하는지 여부 선택 로직</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>256-374</td></tr><tr><td><code>/v1/messages/count_tokens</code>의 z.ai 포워딩 및 자리 표시자 반환</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>1186-1209</td></tr><tr><td>z.ai Anthropic 업스트림 포워딩(JSON 포워딩 + 응답 스트리밍 전달)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>133-219</td></tr><tr><td>z.ai 모델 매핑 규칙(map_model_for_zai)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>13-37</td></tr><tr><td>Header 허용 목록 + z.ai auth 주입</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>70-110</td></tr><tr><td>MCP Search/Reader 리버스 프록시 및 스위치</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L45-L157" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></td><td>45-157</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Vision MCP 최소 구현 위치(완전한 MCP Server 아님)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></td><td>17-37</td></tr><tr><td>Vision 도구 목록 및 제한(tool_specs + 파일 크기 + stream=false)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></td><td>57-270</td></tr><tr><td><code>/v1/models/claude</code> 모델 목록 소스(로컬 매핑, 업스트림 쿼리 안 함)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>84-132</td></tr><tr><td>사용량/예산 모니터링 미구현(문서 선언)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>194-198</td></tr></tbody></table></details>',76)])])}const b=a(i,[["render",d]]);export{u as __pageData,b as default};
